/**
 * Aria Delegation Spectrum — behavioral dimension tracking.
 *
 * Tracks 5 behavioral dimensions as floats in [-1, 1] with exponential decay.
 * Uses a rolling window of InteractionRecords (capped at 50) to measure
 * ongoing player behavior patterns (overtrust ↔ partnership ↔ undertrust).
 *
 * See docs/ARIA_DELEGATION_SPECTRUM.md for full design.
 */

// ── Types ────────────────────────────────────────────────────────────────────

export type DimensionKey =
  | 'goalFraming'
  | 'proposalResponse'
  | 'strategicAuthority'
  | 'curiosityExchange'
  | 'disagreementTolerance';

export interface InteractionRecord {
  tick: number;
  dimension: DimensionKey;
  /** -1 = overtrust signal, 0 = neutral, 1 = undertrust signal */
  direction: -1 | 0 | 1;
  /** Strength of signal, 0.0–1.0 */
  magnitude: number;
  source: 'approve' | 'reject' | 'bulk_approve' | 'query' | 'override';
}

export type DialogueStage =
  | 'advisor'
  | 'questioner'
  | 'peer'
  | 'partner'
  | 'efficient'
  | 'instrumental'
  | 'hollow'
  | 'available'
  | 'quiet'
  | 'dormant';

export interface SpectrumState {
  dimensions: Record<DimensionKey, number>;
  dialogueStage: DialogueStage;
  interactionHistory: InteractionRecord[];
}

export interface SerializedSpectrumState {
  spectrumDimensions: Record<string, number>;
  dialogueStage: string;
  interactionHistory: InteractionRecord[];
}

// ── Constants ────────────────────────────────────────────────────────────────

export const ALL_DIMENSIONS: readonly DimensionKey[] = [
  'goalFraming',
  'proposalResponse',
  'strategicAuthority',
  'curiosityExchange',
  'disagreementTolerance',
] as const;

const MAX_HISTORY = 50;
const DECAY_FACTOR = 0.95;

/** Rapid-switching filter: direction changes within this window */
const RAPID_SWITCH_WINDOW = 10;
const RAPID_SWITCH_THRESHOLD = 3;

/** Consistency weighting thresholds */
const LOW_VARIANCE_THRESHOLD = 0.3;
const HIGH_VARIANCE_THRESHOLD = 0.7;
const HIGH_VARIANCE_DAMPENING = 0.5;

// ── State ────────────────────────────────────────────────────────────────────

let state: SpectrumState = createInitialState();

function createInitialState(): SpectrumState {
  return {
    dimensions: {
      goalFraming: 0,
      proposalResponse: 0,
      strategicAuthority: 0,
      curiosityExchange: 0,
      disagreementTolerance: 0,
    },
    dialogueStage: 'advisor',
    interactionHistory: [],
  };
}

// ── Public API ───────────────────────────────────────────────────────────────

export function getSpectrumState(): Readonly<SpectrumState> {
  return state;
}

export function getDimension(key: DimensionKey): number {
  return state.dimensions[key];
}

export function getDialogueStage(): DialogueStage {
  return state.dialogueStage;
}

export function getInteractionHistory(): readonly InteractionRecord[] {
  return state.interactionHistory;
}

/**
 * Record a new interaction and update the relevant dimension.
 */
export function recordInteraction(record: InteractionRecord): void {
  // Add to rolling window
  state.interactionHistory.push(record);
  if (state.interactionHistory.length > MAX_HISTORY) {
    state.interactionHistory.shift();
  }

  // Check rapid-switching filter for this dimension
  const recentForDim = getRecentForDimension(record.dimension, RAPID_SWITCH_WINDOW);
  if (isRapidSwitching(recentForDim)) {
    // Interaction recorded but contributes 0 to dimension value
    return;
  }

  // Compute consistency weight from variance
  const weight = computeConsistencyWeight(recentForDim);

  // Update dimension: shift toward direction * magnitude, weighted
  const shift = record.direction * record.magnitude * weight;
  const current = state.dimensions[record.dimension];
  const updated = clamp(current + shift * 0.1, -1, 1);
  state.dimensions[record.dimension] = updated;
}

/**
 * Apply exponential decay toward 0 for all dimensions.
 * Call this periodically (e.g., every N ticks or on delegation cycles).
 */
export function applyDecay(): void {
  for (const key of ALL_DIMENSIONS) {
    state.dimensions[key] *= DECAY_FACTOR;
    // Snap to 0 if very close
    if (Math.abs(state.dimensions[key]) < 0.001) {
      state.dimensions[key] = 0;
    }
  }
}

/**
 * Set the dialogue stage directly.
 */
export function setDialogueStage(stage: DialogueStage): void {
  state.dialogueStage = stage;
}

/**
 * Reset all spectrum state (for game restart or testing).
 */
export function resetSpectrum(): void {
  state = createInitialState();
}

// ── Serialization ────────────────────────────────────────────────────────────

export function serializeSpectrum(): SerializedSpectrumState {
  return {
    spectrumDimensions: { ...state.dimensions },
    dialogueStage: state.dialogueStage,
    interactionHistory: state.interactionHistory.slice(),
  };
}

export function restoreSpectrum(serialized: SerializedSpectrumState): void {
  for (const key of ALL_DIMENSIONS) {
    state.dimensions[key] = (serialized.spectrumDimensions[key] as number) ?? 0;
  }
  state.dialogueStage = (serialized.dialogueStage as DialogueStage) || 'advisor';
  state.interactionHistory = serialized.interactionHistory?.slice(0, MAX_HISTORY) ?? [];
}

// ── Internals ────────────────────────────────────────────────────────────────

function getRecentForDimension(dimension: DimensionKey, count: number): InteractionRecord[] {
  const forDim = state.interactionHistory.filter((r) => r.dimension === dimension);
  return forDim.slice(-count);
}

/**
 * Detect rapid switching: ≥ RAPID_SWITCH_THRESHOLD direction changes
 * within RAPID_SWITCH_WINDOW interactions for the same dimension.
 */
function isRapidSwitching(recent: InteractionRecord[]): boolean {
  if (recent.length < 2) return false;
  let changes = 0;
  for (let i = 1; i < recent.length; i++) {
    const prev = recent[i - 1].direction;
    const curr = recent[i].direction;
    if (prev !== 0 && curr !== 0 && prev !== curr) {
      changes++;
    }
  }
  return changes >= RAPID_SWITCH_THRESHOLD;
}

/**
 * Compute consistency weight from variance of directions in the window.
 * Low variance (σ < 0.3) → full weight (1.0).
 * High variance (σ > 0.7) → dampened (0.5).
 * In between → linear interpolation.
 */
function computeConsistencyWeight(recent: InteractionRecord[]): number {
  if (recent.length < 2) return 1.0;

  const values = recent.map((r) => r.direction * r.magnitude);
  const mean = values.reduce((a, b) => a + b, 0) / values.length;
  const variance = values.reduce((sum, v) => sum + (v - mean) ** 2, 0) / values.length;
  const stddev = Math.sqrt(variance);

  if (stddev <= LOW_VARIANCE_THRESHOLD) return 1.0;
  if (stddev >= HIGH_VARIANCE_THRESHOLD) return HIGH_VARIANCE_DAMPENING;

  // Linear interpolation between thresholds
  const t = (stddev - LOW_VARIANCE_THRESHOLD) / (HIGH_VARIANCE_THRESHOLD - LOW_VARIANCE_THRESHOLD);
  return 1.0 - t * (1.0 - HIGH_VARIANCE_DAMPENING);
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}
